composeOverride:
# Generated by McHarbor App Store
services:
  {{serviceName}}:
    image: {{image}}
    container_name: {{containerName}}
    restart: unless-stopped
    depends_on:
      - {{serviceName}}-db
{{ports}}
    volumes:
      - {{env.MEDIAWIKI_IMAGES_PATH}}:/var/www/html/images
  {{serviceName}}-db:
    image: mariadb:11
    container_name: {{containerName}}-db
    restart: unless-stopped
    volumes:
      - {{env.MEDIAWIKI_DB_PATH}}:/var/lib/mysql
    environment:
      MARIADB_DATABASE: {{env.MEDIAWIKI_DB_NAME}}
      MARIADB_USER: {{env.MEDIAWIKI_DB_USER}}
      MARIADB_PASSWORD: {{env.MEDIAWIKI_DB_PASSWORD}}
      MARIADB_ROOT_PASSWORD: {{env.MEDIAWIKI_DB_ROOT_PASSWORD}}
